import {{ Injectable }} from '@nestjs/common';
import {{ MetricsService }} from './models/metrics.model';
import {{ MetricsServiceRepository }} from './repositories/metrics.repository';

@Injectable()
export class MetricsServiceService {{
  constructor(
    private readonly repository: MetricsServiceRepository,
  ) {{}}

  async findAll(): Promise<MetricsService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<MetricsService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<MetricsService>): Promise<MetricsService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<MetricsService>): Promise<MetricsService> {{
    return this.repository.update(id, data);
  }}
}}

